param(
    [string]$BuildDir = ''
)

$ErrorActionPreference = 'Stop'
$LogFile = "$env:SystemRoot\Logs\Invoke-DiskCleanup.log"

function Write-Log {
    param([string]$Message)
    $Entry = "[$(Get-Date -Format 'MM/dd/yyyy HH:mm:ss')] $Message"
    Add-Content -Path $LogFile -Value $Entry -ErrorAction SilentlyContinue
    Write-Output $Entry
}

try {
    If (-not [string]::IsNullOrEmpty($BuildDir) -and (Test-Path -Path $BuildDir)) {
        Write-Log "Removing build directory: $BuildDir"
        Remove-Item -Path $BuildDir -Recurse -Force -ErrorAction SilentlyContinue
    }

    Write-Log "Clearing temp folders"
    Remove-Item -Path $env:SystemRoot\Temp\* -Recurse -Force -ErrorAction SilentlyContinue
    Remove-Item -Path $env:TEMP\* -Recurse -Force -ErrorAction SilentlyContinue

    Write-Log "Removing temp/log files from common locations"
    $scanPaths = @(
        "$env:SystemRoot\Prefetch",
        "$env:SystemRoot\SoftwareDistribution\Download",
        'C:\Windows\Logs\CBS',
        'C:\Windows\Logs\DISM',
        'C:\ProgramData\USOShared\Logs'
    )
    foreach ($scanPath in $scanPaths) {
        if (Test-Path -Path $scanPath) {
            Get-ChildItem -Path $scanPath -Include *.tmp, *.dmp, *.etl, *.log -File -Recurse -Force -ErrorAction SilentlyContinue |
                ForEach-Object {
                    try { Remove-Item $_.FullName -Force -ErrorAction Stop }
                    catch { Write-Log "  Skipped (locked/in-use): $($_.FullName)" }
                }
        }
    }

    Write-Log "Clearing WER folders"
    Remove-Item -Path $env:ProgramData\Microsoft\Windows\WER\Temp\* -Recurse -Force -ErrorAction SilentlyContinue
    Remove-Item -Path $env:ProgramData\Microsoft\Windows\WER\ReportArchive\* -Recurse -Force -ErrorAction SilentlyContinue
    Remove-Item -Path $env:ProgramData\Microsoft\Windows\WER\ReportQueue\* -Recurse -Force -ErrorAction SilentlyContinue

    Write-Log "Clearing BranchCache"
    Clear-BCCache -Force -ErrorAction SilentlyContinue

    Write-Log "Clearing Delivery Optimization cache"
    Delete-DeliveryOptimizationCache -Force -ErrorAction SilentlyContinue

    Write-Log "Clearing recycle bin"
    Clear-RecycleBin -Force -ErrorAction SilentlyContinue

    Write-Log "Clearing event logs"
    Get-WinEvent -ListLog * -ErrorAction SilentlyContinue |
        Where-Object { $_.RecordCount -gt 0 } |
        ForEach-Object {
            Write-Log "  Clearing event log '$($_.LogName)' with $($_.RecordCount) record(s)"
            try {
                wevtutil cl $_.LogName 2>&1 | Out-Null
                if ($LASTEXITCODE -ne 0) { Write-Log "  Failed to clear event log '$($_.LogName)' - Exit Code [$LASTEXITCODE]" }
                else { Write-Log "  Cleared event log '$($_.LogName)'" }
            }
            catch { Write-Log $($_.Exception.Message) }
        }

    Write-Log "Disk cleanup complete."
}
catch {
    Write-Log "FATAL: $($_.Exception.GetType().FullName): $($_.Exception.Message)"
    If ($_.Exception.InnerException) { Write-Log "Inner exception: $($_.Exception.InnerException.Message)" }
    Write-Log $_.ScriptStackTrace
    Exit 1
}

variables.restartVmScript:
param(
    [string]$ResourceManagerUri,
    [string]$UserAssignedIdentityClientId,
    [string]$VmResourceId
)

$ErrorActionPreference = 'Stop'
$WarningPreference = 'SilentlyContinue'

Try {
    # Fix the resource manager URI since only AzureCloud contains a trailing slash
    $ResourceManagerUriFixed = if($ResourceManagerUri[-1] -eq '/'){$ResourceManagerUri.Substring(0,$ResourceManagerUri.Length - 1)} else {$ResourceManagerUri}

    # Get an access token — use UAI client_id when provided, otherwise fall back to system-assigned identity
    $TokenUri = 'http://169.254.169.254/metadata/identity/oauth2/token?api-version=2018-02-01&resource=' + $ResourceManagerUriFixed
    if (-not [string]::IsNullOrEmpty($UserAssignedIdentityClientId)) { $TokenUri += '&client_id=' + $UserAssignedIdentityClientId }
    $AzureManagementAccessToken = (Invoke-RestMethod -Headers @{Metadata="true"} -Uri $TokenUri).access_token

    # Set header for Azure Management API
    $AzureManagementHeader = @{
        'Content-Type'='application/json'
        'Authorization'='Bearer ' + $AzureManagementAccessToken
    }

    # Restart the VM
    $null = Invoke-RestMethod -Headers $AzureManagementHeader -Method 'Post' -Uri $($ResourceManagerUriFixed + $VmResourceId + '/restart?api-version=2024-03-01')
    $VmStatus = Invoke-RestMethod -Headers $AzureManagementHeader -Method 'Get' -Uri $($ResourceManagerUriFixed + $VmResourceId + '/instanceView?api-version=2024-03-01')
    $provisioningState = ($VMStatus.statuses | Where-Object {$_.code -like 'PowerState*'}).code
    While ($provisioningState -ne "PowerState/running") {
        Start-Sleep -Seconds 5
        $VmStatus = Invoke-RestMethod -Headers $AzureManagementHeader -Method 'Get' -Uri $($ResourceManagerUriFixed + $VmResourceId + '/instanceView?api-version=2024-03-01')
        $provisioningState = ($VMStatus.statuses | Where-Object {$_.code -like 'PowerState*'}).code
    }
    Start-Sleep -Seconds 15   
}
catch {
    throw
}

variables.customizationScript:
param(
  [string]$APIVersion,
  [string]$Arguments = '',
  [string]$BlobStorageSuffix,
  [string]$BuildDir = '',
  [string]$Name,
  [string]$Uri,
  [string]$UserAssignedIdentityClientId
)

$ErrorActionPreference = 'Stop'
$LogFile = "$env:SystemRoot\Logs\$Name.log"

function Write-Log {
  param([string]$Message)
  $Entry = "[$(Get-Date -Format 'MM/dd/yyyy HH:mm:ss')] $Message"
  Add-Content -Path $LogFile -Value $Entry -ErrorAction SilentlyContinue
  Write-Output $Entry
}

function Split-ArgumentString {
  param([string]$ArgumentString)

  if ([string]::IsNullOrWhiteSpace($ArgumentString)) { return @() }

  $arguments = @()
  $currentArg = ''
  $inQuotes = $false
  $quoteChar = $null

  for ($i = 0; $i -lt $ArgumentString.Length; $i++) {
    $char = $ArgumentString[$i]
    if (!$inQuotes -and (($char -eq '"' -and ($i -eq 0 -or $ArgumentString[$i - 1] -ne '\')) -or $char -eq "'")) {
      $inQuotes = $true
      $quoteChar = $char
      $currentArg += $char
    }
    elseif ($inQuotes -and $char -eq $quoteChar) {
      $inQuotes = $false
      $quoteChar = $null
      $currentArg += $char
    }
